// Extraer datos del mensaje de WhatsApp
const body = $input.first().json.body;

let from = '';
let messageText = '';
let messageType = '';

try {
  const entry = body.entry?.[0];
  const change = entry?.changes?.[0];
  const value = change?.value;
  const message = value?.messages?.[0];

  from = message?.from || '';
  messageType = message?.type || '';

  if (messageType === 'text') {
    messageText = message?.text?.body?.trim() || '';
  } else if (messageType === 'interactive') {
    const interactive = message?.interactive;
    if (interactive?.type === 'button_reply') {
      messageText = interactive?.button_reply?.id || '';
    } else if (interactive?.type === 'list_reply') {
      messageText = interactive?.list_reply?.id || '';
    }
  }
} catch(e) {
  // Verificación de webhook GET (Meta lo hace al configurar)
}

return [{ json: { from, messageText, messageType, rawBody: body } }];

